/**
 * @name Code injection via eval in ImageMath
 * @description User-controlled data flowing to eval() call in ImageMath.py can lead to code execution
 * @kind path-problem
 * @problem.severity critical
 * @id py/code-injection-imagemath
 * @tags security
 *        external/cwe/cwe-094
 */

import python
import semmle.python.dataflow.new.DataFlow
import semmle.python.dataflow.new.TaintTracking
import semmle.python.dataflow.new.RemoteFlowSources
import semmle.python.Concepts

module EvalInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(Call c |
      c.getFunc().(Name).getId() = "eval" and
      sink = DataFlow::exprNode(c.getArg(0))
    )
  }
}

module EvalInjectionFlow = TaintTracking::Global<EvalInjectionConfig>;
import EvalInjectionFlow::PathGraph

from EvalInjectionFlow::PathNode source, EvalInjectionFlow::PathNode sink
where EvalInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Code injection from $@ to eval().", source.getNode(), "user input"

/**
 * @name Command injection in Pillow
 * @description User-controlled data flowing to command execution functions
 * @kind path-problem
 * @problem.severity critical
 * @id py/command-injection-pil
 * @tags security
 *        external/cwe/cwe-078
 */

import python
import semmle.python.dataflow.new.DataFlow
import semmle.python.dataflow.new.TaintTracking
import semmle.python.dataflow.new.RemoteFlowSources
import semmle.python.Concepts

module CommandInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Command execution sinks
    exists(Call c |
      // subprocess.call, Popen, run, etc
      c.getFunc().(Name).getId().matches("Popen") and
      sink = DataFlow::exprNode(c)
    ) or
    exists(Call c |
      c.getFunc().(Attribute).getAttr() = "system" and
      sink = DataFlow::exprNode(c)
    )
  }
}

module CommandInjectionFlow = TaintTracking::Global<CommandInjectionConfig>;
import CommandInjectionFlow::PathGraph

from CommandInjectionFlow::PathNode source, CommandInjectionFlow::PathNode sink
where CommandInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Command injection from $@.", source.getNode(), "user input"

/**
 * @name Code injection in ImageMath.eval
 * @description User-controlled data flowing to eval() in ImageMath.eval can lead to arbitrary code execution
 * @kind path-problem
 * @problem.severity critical
 * @id py/code-injection-imagemath-eval
 * @tags security
 *        external/cwe/cwe-094
 */

import python
import semmle.python.dataflow.new.DataFlow
import semmle.python.dataflow.new.TaintTracking
import semmle.python.dataflow.new.RemoteFlowSources
import semmle.python.Concepts

module ImageMathEvalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Find eval calls specifically in ImageMath.py
    exists(Call c |
      c.getFunc().(Name).getId() = "eval" and
      c.getLocation().getFile().getBaseName() = "ImageMath.py" and
      sink = DataFlow::exprNode(c.getArg(0))
    )
  }
}

module ImageMathEvalFlow = TaintTracking::Global<ImageMathEvalConfig>;
import ImageMathEvalFlow::PathGraph

from ImageMathEvalFlow::PathNode source, ImageMathEvalFlow::PathNode sink
where ImageMathEvalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Code injection from $@ to eval() in ImageMath.py.", source.getNode(), "user input"
